        language: None,
        scope_id: "test".to_string(),
        source_version: "v1".to_string(),
    };
    let (chunks, _relations) = pipeline.process(&content, &meta).unwrap();
    assert!(!chunks.is_empty(), "chunking should produce at least 1 chunk");

    // Insert each chunk as an entry (skip real embedding — use fake)
    let fake_embedding = vec![0.1_f32; 768];
    for chunk in &chunks {
